import React, { useEffect, useState } from "react";

function Room() {
  const [rooms, setRooms] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [form, setForm] = useState({
    PhongSo: "",
    LoaiPhong: "",
    GiaPhong: "",
    TinhTrang: "trong",
  });
  const [editMode, setEditMode] = useState(false);

  const fetchRooms = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/rooms/managementrooms");
      const data = await res.json();
      const sortedRooms = data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setRooms(sortedRooms);
      setLoading(false);
    } catch (err) {
      setError("Lỗi khi tải dữ liệu");
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRooms();
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleAddRoom = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/rooms/addroom", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          phongso: form.PhongSo,
          loaiphong: form.LoaiPhong,
          giaphong: form.GiaPhong,
          trangthai: form.TinhTrang,
        }),
      });
      const data = await res.json();
      if (res.ok) {
        alert("Thêm phòng thành công!");
        fetchRooms();
        setForm({ PhongSo: "", LoaiPhong: "", GiaPhong: "", TinhTrang: "trong" });
      } else {
        alert(data.error);
      }
    } catch (err) {
      alert("Lỗi khi thêm phòng");
    }
  };

  const handleDelete = async (PhongSo) => {
    if (!window.confirm(`Bạn có chắc chắn muốn xóa phòng ${PhongSo}?`)) return;
    try {
      const res = await fetch("http://localhost:5000/api/rooms/deleteroom", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ PhongSo }),
      });
      const data = await res.json();
      if (res.ok) {
        alert("Xóa thành công!");
        fetchRooms();
      } else {
        alert(data.error);
      }
    } catch (err) {
      alert("Lỗi khi xóa phòng");
    }
  };

  const handleUpdateRoom = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/rooms/updateroom", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (res.ok) {
        alert("Cập nhật thành công!");
        fetchRooms();
        setForm({ PhongSo: "", LoaiPhong: "", GiaPhong: "", TinhTrang: "trong" });
        setEditMode(false);
      } else {
        alert(data.error);
      }
    } catch (err) {
      alert("Lỗi khi cập nhật phòng");
    }
  };

  const handleChangeStatus = async (PhongSo, newStatus) => {
    try {
      const res = await fetch("http://localhost:5000/api/rooms/statusroom", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ PhongSo, TinhTrang: newStatus }),
      });
      const data = await res.json();
      if (res.ok) fetchRooms();
      else alert(data.error);
    } catch (err) {
      alert("Lỗi khi cập nhật trạng thái");
    }
  };

  const handleReport = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/rooms/reportroom");
      const data = await res.json();
      if (res.ok) alert(JSON.stringify(data, null, 2));
      else alert(data.error);
    } catch (err) {
      alert("Lỗi khi lấy báo cáo");
    }
  };

  if (loading) return <p className="text-center mt-5">Đang tải dữ liệu...</p>;
  if (error) return <p className="text-red-500">{error}</p>;

  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold mb-6 text-blue-600">Quản lý phòng</h1>

      {/* Form thêm / sửa phòng */}
      <div className="mb-8 p-6 border rounded-2xl shadow bg-white">
        <h2 className="font-semibold mb-4 text-lg text-gray-700">
          {editMode ? "✏️ Sửa phòng" : "Thêm phòng mới"}
        </h2>
        <div className="grid grid-cols-4 gap-4">
          <input
            type="text"
            name="PhongSo"
            placeholder="Số phòng"
            value={form.PhongSo}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
            disabled={editMode}
          />

          <select
            name="LoaiPhong"
            value={form.LoaiPhong}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
          >
            <option value="">Loại phòng</option>
            <option value="binhthuong(nho)">Bình thường (nhỏ)</option>
            <option value="binhthuong(to)">Bình thường (to)</option>
            <option value="caocap(nho)">Cao cấp (nhỏ)</option>
            <option value="caocap(to)">Cao cấp (to)</option>
            <option value="sangtrong">Sang trọng</option>
          </select>

          <input
            type="number"
            name="GiaPhong"
            placeholder="Giá phòng"
            value={form.GiaPhong}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
          />

          <select
            name="TinhTrang"
            value={form.TinhTrang}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
          >
            <option value="trong">Trống</option>
            <option value="dadat">Đã đặt</option>
          </select>
        </div>

        <div className="mt-4 flex gap-3">
          {editMode ? (
            <>
              <button
                onClick={handleUpdateRoom}
                className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded shadow"
              >
                💾 Lưu thay đổi
              </button>
              <button
                onClick={() => {
                  setEditMode(false);
                  setForm({ PhongSo: "", LoaiPhong: "", GiaPhong: "", TinhTrang: "trong" });
                }}
                className="bg-gray-400 hover:bg-gray-500 text-white px-4 py-2 rounded shadow"
              >
                ❌ Hủy
              </button>
            </>
          ) : (
            <button
              onClick={handleAddRoom}
              className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded shadow"
            >
              ➕ Thêm phòng
            </button>
          )}
        </div>
      </div>

      {/* Nút báo cáo */}
      <button
        onClick={handleReport}
        className="mb-6 bg-purple-500 hover:bg-purple-600 text-white px-5 py-2 rounded shadow"
      >
        📊 Xem báo cáo phòng
      </button>

      {/* Danh sách phòng */}
      <div className="overflow-x-auto shadow rounded-2xl">
        <table className="w-full border-collapse">
          <thead>
            <tr className="bg-blue-100 text-blue-800">
              <th className="border p-3">Phòng số</th>
              <th className="border p-3">Loại phòng</th>
              <th className="border p-3">Giá phòng</th>
              <th className="border p-3">Tình trạng</th>
              <th className="border p-3">Hành động</th>
            </tr>
          </thead>
          <tbody>
            {rooms.map((room, idx) => (
              <tr
                key={room.PhongSo}
                className={idx % 2 === 0 ? "bg-white hover:bg-gray-100" : "bg-gray-50 hover:bg-gray-100"}
              >
                <td className="border p-3 text-center">{room.PhongSo}</td>
                <td className="border p-3 text-center">{room.LoaiPhong}</td>
                <td className="border p-3 text-center">{room.GiaPhong}</td>
                
                {/* Tình trạng dạng select */}
                <td className="border p-3 text-center">
                  <select
                    value={room.TinhTrang}
                    onChange={(e) => handleChangeStatus(room.PhongSo, e.target.value)}
                    className={`p-1 rounded ${
                      room.TinhTrang === "trong" ? "text-green-600" : "text-red-500"
                    }`}
                  >
                    <option value="trong">Trống</option>
                    <option value="dadat">Đã đặt</option>
                  </select>
                </td>

                <td className="border p-3 flex justify-center gap-2">
                  <button
                    onClick={() => {
                      setEditMode(true);
                      setForm(room);
                    }}
                    className="bg-yellow-400 hover:bg-yellow-500 text-white px-3 py-1 rounded shadow"
                  >
                    ✏️ Sửa
                  </button>
                  <button
                    onClick={() => handleDelete(room.PhongSo)}
                    className="bg-red-500 hover:bg-red-600 text-white px-3 py-1 rounded shadow"
                  >
                    🗑 Xóa
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Room;
